// Vendors the ACP SDK's generated Zod schemas into src/agents/acp-vendored/.
//
// The SDK stopped exposing dist/schema/zod.gen.js through its `exports` map in
// v1, but still ships the files in the tarball. Copying them out of the
// installed package keeps Shellular validating with the SDK's own generated
// schemas: bump the SDK and rerun the build, and any upstream schema change
// shows up as a diff in the vendored files (and as type errors if something
// we re-export was renamed or removed).
//
// Runs as part of `build` and `typecheck`. Rewrites files only when content
// actually changed.

import { createRequire } from "node:module";
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const require = createRequire(import.meta.url);

const MODULE_NAME = "@agentclientprotocol/sdk"

// Resolve the installed SDK's dist directory via its main entry ("." is the
// only useful subpath its exports map allows).
const sdkMain = require.resolve(MODULE_NAME);
console.log("ACP module path:", sdkMain);
const sdkDistDir = path.dirname(sdkMain);
const sdkVersion = JSON.parse(
	fs.readFileSync(path.join(sdkDistDir, "..", "package.json"), "utf8"),
).version;
console.log("ACP SDK version:", sdkVersion);

const outDir = path.join(
	path.dirname(fileURLToPath(import.meta.url)),
	"..",
	"src",
	"agents",
	"acp-vendored",
);

const header = `// Vendored from ${MODULE_NAME}@${sdkVersion} — DO NOT EDIT.\n// Regenerated by scripts/vendor-acp-schemas.mjs on every build/typecheck.\n`;

// source (relative to sdk dist) → [target name, import rewrites]
const files = [
  { src: "schema-deserialize.js", out: "schema-deserialize.js", rewrite: [] },
	{
		src: "schema/zod.gen.js",
		out: "zod.gen.js",
		rewrite: [["../schema-deserialize.js", "./schema-deserialize.js"]],
	},
	{ src: "schema/zod.gen.d.ts", out: "zod.gen.d.ts", rewrite: [] },
	{
		src: "schema-deserialize.d.ts",
		out: "schema-deserialize.d.ts",
		rewrite: [],
	},
];

fs.mkdirSync(outDir, { recursive: true });

let changed = 0;
for (const file of files) {
	let content = fs.readFileSync(path.join(sdkDistDir, file.src), "utf8");
	for (const [from, to] of file.rewrite) {
		if (!content.includes(from)) {
			throw new Error(
				`vendor-acp-schemas: expected "${from}" in ${file.src} — the SDK's layout changed, update this script`,
			);
		}
		content = content.replaceAll(from, to);
	}
	content = content.replace(/^\/\/# sourceMappingURL=.*\n?/m, "");
	content = header + content;

	const target = path.join(outDir, file.out);
	const existing = fs.existsSync(target)
		? fs.readFileSync(target, "utf8")
		: null;
	if (existing !== content) {
		fs.writeFileSync(target, content);
		changed++;
	}
}

console.log(
	changed
		? `vendored ACP schemas from ${MODULE_NAME}@${sdkVersion} (${changed} file(s) updated)`
		: `vendored ACP schemas up to date (${MODULE_NAME}@${sdkVersion})`,
);
